import org.springframework.boot.SpringApplication;
import org.springframework.boot.SpringApplicationRunListener;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.ConfigurableApplicationContext;
import org.springframework.core.env.ConfigurableEnvironment;

@SpringBootApplication
public class MyApplication {

    public static void main(String[] args) {
        // SpringApplication orchestrates the full startup
        SpringApplication app = new SpringApplication(MyApplication.class);

        // Add listener to observe each startup phase
        app.addListeners(event ->
            System.out.println("Event fired: " + event.getClass().getSimpleName())
        );

        // Run returns a fully initialized ApplicationContext
        ConfigurableApplicationContext ctx = app.run(args);

        // At this point: env prepared, context refreshed, server started
        System.out.println("Active profiles: " +
            String.join(", ", ctx.getEnvironment().getActiveProfiles()));
        System.out.println("Bean count: " + ctx.getBeanDefinitionCount());
    }
}

import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class EmbeddedServerConfig {

    // Override the default Tomcat factory with custom settings
    @Bean
    public TomcatServletWebServerFactory tomcatFactory() {
        TomcatServletWebServerFactory factory = new TomcatServletWebServerFactory();
        factory.setPort(9090);           // custom port
        factory.setContextPath("/api");  // custom context path
        return factory;
    }

    // Customizer applied to whichever server factory is active
    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> customizer() {
        return factory -> {
            factory.addConnectorCustomizers(connector ->
                connector.setMaxPostSize(10 * 1024 * 1024) // 10 MB max POST
            );
            System.out.println("Tomcat factory customized: port=" + factory.getPort());
        };
    }
}

import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Primary;
import org.springframework.stereotype.Service;

interface NotificationService {
    void send(String message);
}

class EmailNotification implements NotificationService {
    public void send(String msg) { System.out.println("Email: " + msg); }
}

class SmsNotification implements NotificationService {
    public void send(String msg) { System.out.println("SMS: " + msg); }
}

@Configuration
class NotificationConfig {
    @Bean @Primary  // default when no @Qualifier specified
    public NotificationService emailService() { return new EmailNotification(); }

    @Bean
    public NotificationService smsService() { return new SmsNotification(); }
}

@Service
class AlertService {
    private final NotificationService primary;   // gets emailService via @Primary
    private final NotificationService sms;       // explicit qualifier

    public AlertService(
            NotificationService primary,
            @Qualifier("smsService") NotificationService sms) {
        this.primary = primary;
        this.sms = sms;
    }

    public void alert(String msg) { primary.send(msg); sms.send(msg); }
}

