import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

// ---- @Controller: returns view names for template rendering ----
@Controller
@RequestMapping("/web")
class WebController {

    // Returns a Thymeleaf/FreeMarker view name — NOT serialized to JSON
    @GetMapping("/users/{id}")
    public String getUserPage(@PathVariable Long id, Model model) {
        model.addAttribute("userId", id);
        model.addAttribute("name", "Alice");
        return "user-profile";  // resolves to templates/user-profile.html
    }

    // When you DO want JSON from a @Controller method, add @ResponseBody explicitly
    @GetMapping("/users/{id}/json")
    @ResponseBody
    public String getUserJson(@PathVariable Long id) {
        return "{\"id\":" + id + "}";  // serialized because of @ResponseBody
    }
}

// ---- @RestController = @Controller + @ResponseBody on every method ----
@RestController  // implies @ResponseBody globally — every method returns JSON/text
@RequestMapping("/api")
class ApiController {

    // Return value auto-serialized to JSON via Jackson (no @ResponseBody needed)
    @GetMapping("/users/{id}")
    public UserDto getUser(@PathVariable Long id) {
        return new UserDto(id, "Alice", "alice@example.com");
    }

    @PostMapping("/users")
    public ResponseEntity<UserDto> createUser(@RequestBody UserDto dto) {
        System.out.println("Creating user: " + dto.name());
        return ResponseEntity.status(201).body(dto);
    }
}

record UserDto(Long id, String name, String email) {}

