import jakarta.annotation.PostConstruct;
import jakarta.annotation.PreDestroy;
import org.springframework.beans.BeansException;
import org.springframework.beans.factory.BeanNameAware;
import org.springframework.beans.factory.DisposableBean;
import org.springframework.beans.factory.InitializingBean;
import org.springframework.context.ApplicationContext;
import org.springframework.context.ApplicationContextAware;
import org.springframework.stereotype.Component;

@Component
public class LifecycleBean
        implements BeanNameAware, ApplicationContextAware,
                   InitializingBean, DisposableBean {

    public LifecycleBean() {
        System.out.println("[1] Constructor called");         // Phase 1
    }

    // Phase 3a — *Aware interfaces
    @Override
    public void setBeanName(String name) {
        System.out.println("[3a] BeanNameAware: name = " + name);
    }

    @Override
    public void setApplicationContext(ApplicationContext ctx) throws BeansException {
        System.out.println("[3b] ApplicationContextAware: ctx ready");
    }

    // Phase 5 — @PostConstruct (JSR-250), run before afterPropertiesSet
    @PostConstruct
    public void postConstruct() {
        System.out.println("[5] @PostConstruct: dependencies injected, run setup");
    }

    // Phase 6 — InitializingBean contract
    @Override
    public void afterPropertiesSet() {
        System.out.println("[6] InitializingBean.afterPropertiesSet(): final init");
    }

    // Phase 10 — @PreDestroy (JSR-250), before destroy()
    @PreDestroy
    public void preDestroy() {
        System.out.println("[10] @PreDestroy: releasing resources");
    }

    // Phase 11 — DisposableBean contract
    @Override
    public void destroy() {
        System.out.println("[11] DisposableBean.destroy(): final cleanup");
    }
}
// Full order: Constructor -> Inject -> Aware -> BPP.before -> @PostConstruct
//          -> afterPropertiesSet -> BPP.after(AOP) -> READY
//          -> @PreDestroy -> destroy()

import org.springframework.beans.factory.annotation.Value;
