// --- Approach 2: @ConfigurationProperties — typed property group ---
@ConfigurationProperties(prefix = "app.mail")   // binds app.mail.* keys
public class MailProperties {
    @NotBlank
    private String host;            // app.mail.host
    private int port = 587;         // app.mail.port  (relaxed: port)
    @Min(1)
    private int retries = 3;        // app.mail.retries

    public String getHost() { return host; }
    public void setHost(String host) { this.host = host; }
    public int getPort() { return port; }
    public void setPort(int port) { this.port = port; }
    public int getRetries() { return retries; }
    public void setRetries(int retries) { this.retries = retries; }
}

// Register MailProperties as a bean and inject it
@Component
@EnableConfigurationProperties(MailProperties.class)
class MailService {
    private final MailProperties cfg;
    MailService(MailProperties cfg) { this.cfg = cfg; }
    public void send(String to, String body) {
        System.out.println("Connecting to " + cfg.getHost() + ":" + cfg.getPort());
        System.out.println("Sending to " + to + " (retries=" + cfg.getRetries() + ")");
    }
}
