import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

@Component
public class ConfigPrecedenceDemo {

    // Spring resolves from merged PropertySources in priority order:
    // 1. Command-line args  2. OS env vars  3. application-{profile}.yml
    // 4. application.yml   5. application-{profile}.properties
    // 6. application.properties  7. @PropertySource  8. Defaults
    @Value("${server.port}")
    private int resolvedPort;  // will be 9090 (yml wins over properties)

    @Value("${app.feature.enabled}")
    private boolean featureEnabled;  // false (yml wins)

    public void printResolved() {
        System.out.println("Effective port   : " + resolvedPort);
        System.out.println("Feature enabled  : " + featureEnabled);
        // Best practice: use ONE format (yml preferred for structure)
    }
}

import org.springframework.boot.actuate.endpoint.annotation.Endpoint;
import org.springframework.boot.actuate.endpoint.annotation.ReadOperation;
