import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.stereotype.Component;
import java.util.Map;

// --- Custom HealthIndicator: appears under /actuator/health ---
@Component
public class ExternalApiHealthIndicator implements HealthIndicator {

    private static final String API_URL = "https://api.example.com/ping";

    @Override
    public Health health() {
        boolean reachable = checkApi();
        if (reachable) {
            return Health.up()
                .withDetail("url", API_URL)
                .withDetail("responseTime", "42ms")
                .build();
        }
        return Health.down()
            .withDetail("url", API_URL)
            .withDetail("error", "Connection timed out")
            .build();
    }

    private boolean checkApi() {
        // In production: use RestTemplate/WebClient with timeout
        System.out.println("Pinging external API...");
        return true;  // simulate success
    }
}

