import org.springframework.boot.autoconfigure.condition.ConditionalOnClass;
import org.springframework.boot.autoconfigure.condition.ConditionalOnMissingBean;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Conditional;
import org.springframework.context.annotation.ConditionContext;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.ConfigurationCondition;
import org.springframework.core.type.AnnotatedTypeMetadata;

// --- 1. Built-in @ConditionalOnClass: register only if Jedis is on classpath ---
@Configuration
@ConditionalOnClass(name = "redis.clients.jedis.Jedis")  // classpath check via reflection
class RedisAutoConfig {
    @Bean
    @ConditionalOnMissingBean  // skip if user already defined a cache bean
    public String redisCache() {
        System.out.println("Auto-configuring Redis cache (Jedis found on classpath)");
        return "redis://localhost:6379";
    }
}

// --- 2. @ConditionalOnProperty: activate based on property value ---
@Configuration
class FeatureConfig {
    @Bean
    @ConditionalOnProperty(name = "app.feature.metrics", havingValue = "true",
                           matchIfMissing = false)
    public String metricsCollector() {
        System.out.println("Metrics collector enabled via app.feature.metrics=true");
        return "prometheus-collector";
    }
}

// --- 3. Custom @Conditional: register only on Linux ---
class OnLinuxCondition implements ConfigurationCondition {
    @Override
    public ConfigurationPhase getConfigurationPhase() {
        return ConfigurationPhase.REGISTER_BEAN;
    }
    @Override
    public boolean matches(ConditionContext ctx, AnnotatedTypeMetadata metadata) {
        String os = ctx.getEnvironment().getProperty("os.name", "");
        boolean isLinux = os.toLowerCase().contains("linux");
        System.out.println("OnLinuxCondition: os=" + os + ", matches=" + isLinux);
        return isLinux;
    }
}

@Configuration
class PlatformConfig {
    @Bean
    @Conditional(OnLinuxCondition.class)
    public String linuxOptimizer() {
        return "epoll-event-loop";
    }
}

