// --- How AutoConfigurationImportSelector.selectImports() works internally ---
class HowItWorks {
    // 1. @EnableAutoConfiguration triggers AutoConfigurationImportSelector
    // 2. selectImports() calls SpringFactoriesLoader / AutoConfiguration.imports reader
    // 3. All candidate class names loaded from META-INF files
    // 4. Exclusion list (from exclude attribute or property) is subtracted
    // 5. @Conditional checks filter remaining candidates
    // 6. Surviving class names returned — Spring imports them as @Configuration
    public static void explain() {
        System.out.println("selectImports() returns class names to import as @Configuration");
        System.out.println("Excluded classes are removed BEFORE @Conditional evaluation");
    }
}

import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.embedded.jetty.JettyServletWebServerFactory;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.boot.web.server.Ssl;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class EmbeddedContainerConfig {

    // --- Override factory to use Jetty instead of Tomcat ---
    // (exclude spring-boot-starter-tomcat, include spring-boot-starter-jetty)
    @Bean
    public JettyServletWebServerFactory jettyFactory() {
        JettyServletWebServerFactory factory = new JettyServletWebServerFactory();
        factory.setPort(8443);
        factory.setContextPath("/myapp");
        factory.addServerCustomizers(server -> {
            // Low-level Jetty server customization
            System.out.println("Jetty server customized: threads=" +
                server.getThreadPool());
        });
        return factory;
    }

    // --- WebServerFactoryCustomizer: portable across Tomcat/Jetty/Undertow ---
    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tomcatCustomizer() {
        return factory -> {
            factory.setPort(8080);
            factory.setContextPath("");

            // Enable SSL
            Ssl ssl = new Ssl();
            ssl.setEnabled(false);  // set true in prod with keystore config
            factory.setSsl(ssl);

            // Connector-level tuning
            factory.addConnectorCustomizers(connector -> {
                connector.setMaxPostSize(5 * 1024 * 1024);  // 5 MB max POST body
                connector.setAttribute("maxThreads", 200);
            });

            System.out.println("Tomcat customized — port: " + factory.getPort());
        };
    }
}
// application.yml equivalents (no code needed for simple cases):
//   server:
//     port: 8080
//     servlet:
//       context-path: /myapp
//     tomcat:
//       max-threads: 200
//       max-http-form-post-size: 5MB

import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.stereotype.Component;
import javax.validation.constraints.NotBlank;
import javax.validation.constraints.Min;

@ConfigurationProperties(prefix = "app.datasource")
public class DataSourceProperties {
    @NotBlank
    private String url;
    private String username = "sa";
    @Min(1)
    private int maxPoolSize = 10; // relaxed binding: max-pool-size -> maxPoolSize

    public String getUrl() { return url; }
    public void setUrl(String url) { this.url = url; }
    public int getMaxPoolSize() { return maxPoolSize; }
    public void setMaxPoolSize(int s) { this.maxPoolSize = s; }
}

@Component
@EnableConfigurationProperties(DataSourceProperties.class)
class AppService {
    private final DataSourceProperties props;
    AppService(DataSourceProperties props) { this.props = props; }
