import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Component;

// Circular dependency: A -> B -> A
// Works ONLY with setter/field injection (not constructor)
@Component
class ServiceA {
    private ServiceB serviceB;

    // @Lazy breaks the cycle by injecting a proxy first
    @Autowired
    public void setServiceB(@Lazy ServiceB serviceB) {
        this.serviceB = serviceB;
        System.out.println("ServiceA initialized with ServiceB proxy");
    }

    public void doWork() {
        System.out.println("ServiceA.doWork -> calling ServiceB");
        serviceB.assist();
    }
}

@Component
class ServiceB {
    private final ServiceA serviceA;

    // Constructor injection — Spring places A in singletonFactories
    // before B starts, so A's partially-initialized instance is available
    @Autowired
    public ServiceB(ServiceA serviceA) {
        this.serviceA = serviceA;
        System.out.println("ServiceB initialized with ServiceA");
    }

    public void assist() {
        System.out.println("ServiceB.assist() called");
    }
}
// To avoid circular deps entirely, prefer refactoring:
// extract shared logic into a third service with no back-reference.

