import org.springframework.beans.factory.BeanFactory;
import org.springframework.beans.factory.support.DefaultListableBeanFactory;
import org.springframework.context.ApplicationContext;
import org.springframework.context.annotation.AnnotationConfigApplicationContext;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
class AppConfig {
    @Bean
    public String greeting() { return "Hello, Spring!"; }
}

public class ContextVsFactory {
    public static void main(String[] args) {
        // --- BeanFactory: raw, lightweight, lazy initialization ---
        DefaultListableBeanFactory rawFactory = new DefaultListableBeanFactory();
        // Beans must be registered manually; no classpath scanning
        System.out.println("BeanFactory bean count: " + rawFactory.getBeanDefinitionCount());

        // --- ApplicationContext: feature-rich, eager singleton init ---
        ApplicationContext ctx =
            new AnnotationConfigApplicationContext(AppConfig.class);

        // Extras ApplicationContext adds over BeanFactory:
        String msg = ctx.getBean(String.class);         // bean retrieval
        System.out.println(msg);                         // "Hello, Spring!"
        System.out.println("Env: " + ctx.getEnvironment().getProperty("java.version"));
        ctx.publishEvent(new org.springframework.context.event.ContextStartedEvent(ctx));
        System.out.println("Message: " +
            ctx.getMessage("welcome", null, java.util.Locale.ENGLISH)); // i18n

        ((AnnotationConfigApplicationContext) ctx).close();
    }
}

