import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

public class HashMapInternals {

    public static void main(String[] args) {
        // Default capacity=16, load factor=0.75
        // Resize triggers at 16 * 0.75 = 12 entries
        Map<String, Integer> scores = new HashMap<>(16, 0.75f);

        scores.put("Alice", 95);   // bucket = "Alice".hashCode() & 15
        scores.put("Bob",   87);
        scores.put("Carol", 92);

        // Deliberate collision: same bucket, different keys -> linked list -> tree
        scores.put("Aa", 1);  // "Aa" and "BB" have same hashCode in Java
        scores.put("BB", 2);  // both land in the same bucket
        System.out.println("Aa hash: " + "Aa".hashCode());
        System.out.println("BB hash: " + "BB".hashCode());

        // get() is O(1) avg; O(log n) if bucket converted to red-black tree
        System.out.println("Score of Alice: " + scores.get("Alice"));

        // null key allowed (stored in bucket 0)
        scores.put(null, -1);
        System.out.println("Null key value: " + scores.get(null));

        System.out.println("Total entries: " + scores.size());
    }
}

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class ConcurrentHashMapDemo {

    public static void main(String[] args) throws InterruptedException {
        // Java 8+: node-level CAS — no segment locks
        ConcurrentHashMap<String, AtomicInteger> wordCount = new ConcurrentHashMap<>();

        ExecutorService pool = Executors.newFixedThreadPool(8);
        String[] words = {"java", "spring", "java", "concurrency", "spring", "java"};

        for (String word : words) {
            pool.submit(() -> {
                // computeIfAbsent is atomic — only one thread initializes the key
                wordCount.computeIfAbsent(word, k -> new AtomicInteger(0))
                         .incrementAndGet();
            });
        }

        pool.shutdown();
        pool.awaitTermination(5, TimeUnit.SECONDS);

        // Read operations are lock-free (volatile visibility)
        wordCount.forEach((word, count) ->
            System.out.printf("%-15s -> %d%n", word, count.get()));

        // Atomic bulk operation
        long total = wordCount.reduceValuesToLong(2, AtomicInteger::get, 0, Long::sum);
        System.out.println("Total words processed: " + total);
    }
}

import java.util.concurrent.*;

public class ThreadPoolSizingDemo {

    public static void main(String[] args) throws Exception {
        int cpus = Runtime.getRuntime().availableProcessors();

        // CPU-bound tasks: size = number of cores
        ExecutorService cpuPool = Executors.newFixedThreadPool(cpus);

        // IO-bound tasks: size = cores * (1 + wait/compute ratio)
        // Assume 80% waiting, 20% computing -> ratio = 4 -> size = cpus * 5
        int ioThreads = cpus * (1 + 4);
        ExecutorService ioPool = Executors.newFixedThreadPool(ioThreads);

        // Custom ThreadPoolExecutor with bounded queue + rejection policy
        ThreadPoolExecutor customPool = new ThreadPoolExecutor(
            cpus,            // corePoolSize
            cpus * 2,        // maximumPoolSize
            60, TimeUnit.SECONDS,       // keepAliveTime for idle threads
            new ArrayBlockingQueue<>(500),  // bounded task queue
            Executors.defaultThreadFactory(),
            new ThreadPoolExecutor.CallerRunsPolicy() // slow down producer on overflow
        );

        // Submit tasks
        Future<String> result = customPool.submit(() -> {
            Thread.sleep(10);
            return "task-done on " + Thread.currentThread().getName();
        });
        System.out.println(result.get());

        // Graceful shutdown
        customPool.shutdown();
        customPool.awaitTermination(30, TimeUnit.SECONDS);
        cpuPool.shutdownNow();
        ioPool.shutdownNow();
        System.out.println("All pools shut down. CPUs: " + cpus);
    }
}

import java.lang.management.ManagementFactory;
import java.lang.management.ThreadMXBean;
import java.util.concurrent.locks.ReentrantLock;
import java.util.concurrent.TimeUnit;

public class DeadlockDemo {
    private static final ReentrantLock lockA = new ReentrantLock();
    private static final ReentrantLock lockB = new ReentrantLock();

    public static void main(String[] args) throws InterruptedException {
        // Prevention strategy: use tryLock with timeout instead of lock()
        Thread t1 = new Thread(() -> {
            try {
                // Always acquire in the SAME order (lockA before lockB)
                if (lockA.tryLock(1, TimeUnit.SECONDS)) {
                    try {
                        System.out.println("T1 acquired A");
                        Thread.sleep(50);
                        if (lockB.tryLock(1, TimeUnit.SECONDS)) {
                            try { System.out.println("T1 acquired B — work done"); }
                            finally { lockB.unlock(); }
                        } else { System.out.println("T1 timed out on B — backing off"); }
                    } finally { lockA.unlock(); }
                }
            } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
        });

        t1.start();
        t1.join();

        // Detect existing deadlocks programmatically
        ThreadMXBean mxBean = ManagementFactory.getThreadMXBean();
        long[] deadlocked = mxBean.findDeadlockedThreads();
        System.out.println("Deadlocked threads: " +
            (deadlocked == null ? 0 : deadlocked.length));
    }
}

import java.lang.management.GarbageCollectorMXBean;
import java.lang.management.ManagementFactory;
import java.util.ArrayList;
import java.util.List;

public class GCAlgorithmsDemo {

    public static void main(String[] args) {
        // Print which GC algorithms are active for this JVM run
        for (GarbageCollectorMXBean gc : ManagementFactory.getGarbageCollectorMXBeans()) {
            System.out.printf("GC: %-30s | Collections: %d | Time: %dms%n",
                gc.getName(), gc.getCollectionCount(), gc.getCollectionTime());
        }
        // JVM flags to select GC (pass on command line):
        // G1GC  (default Java 9+):  -XX:+UseG1GC
        // ZGC   (sub-ms pauses):    -XX:+UseZGC
        // ParallelGC (throughput):  -XX:+UseParallelGC
        // SerialGC  (single thread):-XX:+UseSerialGC

        // Demonstrate generational GC: allocate lots of short-lived objects
        System.out.println("\nAllocating short-lived objects (Young Gen pressure)...");
        for (int i = 0; i < 10_000; i++) {
            @SuppressWarnings("unused")
            byte[] garbage = new byte[1024]; // dies in Eden — collected by minor GC
        }

        // Long-lived object promoted to Old Gen
        List<byte[]> longLived = new ArrayList<>();
        for (int i = 0; i < 100; i++) {
            longLived.add(new byte[10_240]); // survives -> Old Gen
        }

        System.gc(); // hint (not guaranteed)
        System.out.println("After GC hint:");
        for (GarbageCollectorMXBean gc : ManagementFactory.getGarbageCollectorMXBeans()) {
            System.out.printf("  %s -> %d collections%n",
                gc.getName(), gc.getCollectionCount());
        }
        System.out.println("Long-lived objects still reachable: " + longLived.size());
    }
}

